changeSet.sql:
-- Payments CREATE TABLE IF NOT EXISTS fin_payments ( id Integer not null, payment_number VARCHAR(50) UNIQUE NOT NULL, payment_date DATE NOT NULL, amount DECIMAL(15,2) NOT NULL, payment_method VARCHAR(50) NOT NULL, reference_number VARCHAR(50), notes TEXT, journal_entry_id INTEGER REFERENCES journal_entries(id), CONSTRAINT fin_payments_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS fin_payments_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY fin_payments.id;
CREATE TABLE IF NOT EXISTS transactions_payments ( id bigint not null, payment_id INTEGER REFERENCES fin_payments(id), partner_id BIGINT , doc_id bigint , amount_applied DECIMAL(15,2) NOT NULL, CONSTRAINT customer_payments_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS transactions_payments_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY transactions_payments.id;
